int numSquares(int n) {
    int* dp = malloc((n + 1) * sizeof(int));
    for (int i = 0; i <= n; i++) dp[i] = 2147483647;
    dp[0] = 0;
    for (int i = 1; i <= n; i++)
        for (int j = 1; j * j <= i; j++) {
            int v = dp[i - j * j] + 1;
            if (v < dp[i]) dp[i] = v;
        }
    int ans = dp[n];
    free(dp);
    return ans;
}
